import { getPasswordStrength } from "../lib/utils";


export default function Profile() {
  const navigate = useNavigate();
  const { user, login, logout } = useAuth();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  // Edit mode states
  const [isEditing, setIsEditing] = useState(false);
  const [shouldChangePassword, setShouldChangePassword] = useState(false);

  // States for delete account
  const [showDeleteForm, setShowDeleteForm] = useState(false);
  const [deletePassword, setDeletePassword] = useState("");
  const [deleteLoading, setDeleteLoading] = useState(false);
  const [deleteError, setDeleteError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    name: "",
    email: "",
    currentPassword: "",
    newPassword: "",
    confirmPassword: "",
  });

  const passwordStrength = getPasswordStrength(formData.newPassword);

  useEffect(() => {
    if (user) {
      setFormData((prev) => ({
        ...prev,
        name: user.name,
        email: user.email,
        currentPassword: "",
        newPassword: "",
        confirmPassword: "",
      }));
    }
  }, [user]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
    setError(null);
    setSuccess(null);
  };

  const handleEditToggle = () => {
    if (isEditing) {
      // If we were editing and click back/cancel, reset to user data
      if (user) {
        setFormData((prev) => ({
          ...prev,
          name: user.name,
          email: user.email,
          currentPassword: "",
          newPassword: "",
          confirmPassword: "",
        }));
      }
      setIsEditing(false);
      setShouldChangePassword(false);
      setError(null);
      setSuccess(null);
    } else {
      setIsEditing(true);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEditing) {
      setIsEditing(true);
      return;
    }

    if (!user) return;

    if (shouldChangePassword) {
      if (!formData.currentPassword) {
        setError("Debes ingresar tu contraseña actual para cambiarla");
        return;
      }
      if (formData.newPassword !== formData.confirmPassword) {
        setError("Las contraseñas nuevas no coinciden");
        return;
      }
      if (formData.newPassword.length < 8) {
        setError("La nueva contraseña debe tener al menos 8 caracteres");
        return;
      }
    }

    setLoading(true);
    setError(null);
    setSuccess(null);

    try {
      const updatedUser = await updateUser(user.userResourceId, {
        name: formData.name,
        email: formData.email,
        currentPassword: shouldChangePassword
          ? formData.currentPassword
          : undefined,
        newPassword: shouldChangePassword ? formData.newPassword : undefined,
      });

      login(updatedUser);
      setSuccess("Información actualizada correctamente");
      setIsEditing(false);
      setShouldChangePassword(false);
      setFormData((prev) => ({
        ...prev,
        currentPassword: "",
        newPassword: "",
        confirmPassword: "",
      }));
    } catch (err: any) {
      setError(err.message || "Error al actualizar el perfil");
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteAccount = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !deletePassword) return;

    setDeleteLoading(true);
    setDeleteError(null);

    try {
      await deleteUser(user.userResourceId, deletePassword);
      logout();
      navigate("/");
    } catch (err: any) {
      setDeleteError(err.message || "Error al eliminar la cuenta");
    } finally {
      setDeleteLoading(false);
    }
  };

  if (!user) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4">
        <span className="material-symbols-outlined text-stone-300 text-6xl">
          person_off
        </span>
        <p className="text-stone-500 font-medium">
          Por favor inicia sesión para ver tu perfil.
        </p>
      </div>
    );
  }

